#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Calculate numerator: 2i+1
        int numerator = 2 * i + 1;

        // Calculate denominator: i²-1
        double denominator = pow(i, 2) - 1;

        // Apply alternating signs
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = n; i >= 1; i--) {
        for (int j = 0; j < i; j++) {
            printf("%d", i);
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int numbers[5], position, score = 0;
    char guess;
    for (int i = 0; i < 5; i++) numbers[i] = rand() % 10 + 1;
    printf("Numbers: ");
    for (int i = 0; i < 5; i++) {
        if (i == position - 1) printf("%d ", numbers[i]);
        else printf("* ");
    }
    printf("\nPick a number between 1 and 5: ");
    if (scanf("%d %c", &position, &guess) == 2) score += 5;
    printf("win %d points\n", score);
    return 0;
}
